// 1. Pega os resultados da busca vetorial
const resultados = $input.all().map(item => item.json);

// 2. Pega a Task Original (Recuperamos do nó de validação para garantir)
// OBS: Ajuste o nome do nó dentro de $('...') se tiver mudado.
const taskOriginal = $('Validação e normalização').first().json;

// 3. Monta o histórico formatado para o GPT (RAG)
const referenciasFormatadas = resultados
  .filter(r => r.similarity > 0.70) // Filtra lixo
  .slice(0, 5) // Pega só top 5
  .map(r => `- [Similaridade: ${Math.round(r.similarity*100)}%] ${r.task_name} (Prioridade Antiga: ${r.prioridade})`)
  .join('\n');

// 4. Retorna tudo num pacote só para o GPT
return [{
  json: {
    // Passamos os dados da tarefa AQUI para não dar erro de Paired Item depois
    taskAtual: {
        titulo: taskOriginal.nomeOriginal,
        descricao: taskOriginal.descricaoOriginal
    },
    contextoRAG: referenciasFormatadas || "Nenhum histórico relevante encontrado.",
    usarGPT: true // Força a ida ao GPT
  }
}];

// Pega o primeiro item de entrada
const input0 = $input.all()[0];

// CORREÇÃO AQUI: O conteúdo do chat fica em message.content, não em text
const resposta = input0.json.message ? input0.json.message.content : input0.json.text;

let decisaoGPT;

try {
  // Validação de segurança se a resposta vier vazia
  if (!resposta) throw new Error('Resposta do GPT veio vazia ou em formato desconhecido');

  // Tenta extrair o JSON da resposta usando regex (busca o primeiro { ... })
  const match = resposta.match(/\{[\s\S]*\}/);
  if (match) {
    decisaoGPT = JSON.parse(match[0]);
  } else {
    throw new Error('Formato JSON não encontrado na resposta');
  }
} catch (error) {
  // Fallback: Retorna erro visível para você saber o que houve
  decisaoGPT = {
    equipe: 'ERRO',
    prioridade: 'ERRO',
    justificativa: `Falha no Code Node: ${error.message}`
  };
}

// Retorna os dados corrigidos
return [
  {
    json: {
      equipe: decisaoGPT.equipe || 'suporte', // Garante valor default
      prioridade: decisaoGPT.prioridade || 3,
      justificativa: decisaoGPT.justificativa || 'Sem justificativa',
      fonte: 'GPT-RAG',
      // Mantém o ID da tarefa original
      taskId: $json.taskAtual ? $json.taskAtual.id : 'ID_NAO_ENCONTRADO'
    },
    // Mantém o pareamento com o item anterior
    pairedItem: {
      item: 0
    }
  }
];

// Busca os dados do nó anterior (Get a task)
const task = $input.item.json; 

// Extrai nome e descrição da task completa
const descricao = (task.description || task.name || '').trim();
const nome = (task.name || '').trim();

// Validação com tratamento de erro
if (!descricao || descricao.length < 10) {
  // Em vez de lançar erro, retorna objeto com flag de erro
  return [{
    json: {
      error: true,
      message: 'Descrição muito curta ou inexistente',
      taskId: task.id
    }
  }];
}

function normalizarTexto(texto) {
  // Remove acentos, pontuação e normaliza o texto
  return texto.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/[^\w\s]/g, ' ').replace(/\s+/g, ' ').trim();
}

const textoCompleto = `${nome} ${descricao}`;
const textoNormalizado = normalizarTexto(textoCompleto);

// Retorna o objeto JSON com os dados validados
return [{
  json: {
    error: false,
    taskId: task.id,
    nomeOriginal: nome,
    descricaoOriginal: descricao,
    textoCompleto: textoCompleto,
    textoNormalizado: textoNormalizado,
  }
}];

const embedding = $('OpenAI - Gerar Embedding').item.json.data[0].embedding;
const supabaseUrl = $('Set - Configurações Supabase').first().json.supabaseUrl;

const body = {
  query_embedding: embedding,
  match_threshold: 0.1,
  match_count: 5
};

console.log('URL:', `${supabaseUrl}/rest/v1/rpc/match_tasks_rag`);
console.log('Body:', JSON.stringify(body).substring(0, 200));
console.log('Tamanho do embedding:', embedding.length);

return [{ json: body }];

